sys_script_include.script:
var AROPAjax = Class.create();
AROPAjax.prototype = Object.extendsObject(AbstractAjaxProcessor, {

    triggerAssessment: function() {
        try {
            // Block if already running
            var running = new GlideRecord('x_snc_airop_assessment_run');
            running.addQuery('status', 'running');
            running.setLimit(1);
            running.query();
            if (running.next()) {
                return 'RUNNING|' + running.getUniqueValue() + '|' + running.getDisplayValue('name');
            }

            // Fire scheduled job immediately
            var job = new GlideRecord('sysauto_script');
            job.addQuery('name', 'AIROP Scheduled Assessment');
            job.setLimit(1);
            job.query();
            if (!job.next()) {
                return 'ERROR|Scheduled job not found. Contact your administrator.';
            }
            job.setValue('next_action', new GlideDateTime());
            job.setValue('active', true);
            job.update();

            // Create run record to redirect user to
            var run = new GlideRecord('x_snc_airop_assessment_run');
            run.setValue('name', 'AIROP Run - ' + new GlideDateTime());
            run.setValue('status', 'running');
            run.setValue('run_date', new GlideDateTime());
            var runId = run.insert();

            return 'OK|' + runId;

        } catch(e) {
            return 'ERROR|' + e.toString();
        }
    },


    generateExport: function() {
        try {
            var runId = this.getParameter("sysparm_run_id");
            if (!runId) return JSON.stringify({ success: false, message: "No run ID provided" });
            var exporter = new x_snc_airop.AROPExporter();
            var result = exporter.generateExportCSV(runId);
            return JSON.stringify(result);
        } catch(e) {
            return JSON.stringify({ success: false, message: e.message });
        }
    },
    type: 'AROPAjax'
});
